import React, { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { IoIosMenu } from "react-icons/io";
import { RxCross2 } from "react-icons/rx";
import { useStoreContext } from "../contextApi/ContextApi";


const Navbar = () => {
  const navigate = useNavigate();
  const { token, setToken } = useStoreContext();
  const path = useLocation().pathname;
  const [navbarOpen, setNavbarOpen] = useState(false);

  const onLogOutHandler = () => {
    setToken(null);
    localStorage.removeItem("JWT_TOKEN");
    navigate("/login");
  };

  return (
    <div className="h-16 bg-custom-gradient  z-50 flex items-center sticky top-0 ">
      <div className="lg:px-14 sm:px-8 px-4 w-full flex justify-between">
        <Link to="/">
          <h1 className="font-bold text-3xl text-white italic sm:mt-0 mt-2">
            Linklytics
          </h1>
        </Link>
        <ul
          className={`flex sm:gap-10 gap-4 sm:items-center sm:mt-1 sm:pt-0 pt-3 text-slate-800 sm:static absolute left-0 top-[62px] sm:shadow-none shadow-md ${
            navbarOpen ? "h-fit sm:pb-0 pb-5" : "h-0 overflow-hidden"
          }  transition-all duration-100 sm:h-fit sm:bg-none  bg-custom-gradient sm:w-fit w-full sm:flex-row flex-col px-4 sm:px-0`}
        >
          <li className="hover:text-btnColor font-[500]  transition-all duration-150">
            <Link
              className={`${
                path === "/" ? "text-white font-semibold" : "text-gray-200"
              }`}
              to="/"
            >
              Home
            </Link>
          </li>
          <li className="hover:text-btnColor font-[500]  transition-all duration-150">
            <Link
              className={`${
                path === "/about" ? "text-white font-semibold" : "text-gray-200"
              }`}
              to="/about"
            >
              About
            </Link>
          </li>
          <li className="hover:text-btnColor font-[500]  transition-all duration-150">
            <Link
              className={`${
                path === "/scanner" ? "text-white font-semibold" : "text-gray-200"
              }`}
              to="/scanner"
            >
              URL Scanner
            </Link>
          </li>
          {token && (
            <li className="hover:text-btnColor font-[500]  transition-all duration-150">
            <Link
              className={`${
                path === "/dashboard" ? "text-white font-semibold" : "text-gray-200"
              }`}
              to="/dashboard"
            >
              Dashboard
            </Link>
          </li>
          )}
          {!token && (
            <Link to="/register">
              <li className=" sm:ml-0 -ml-1 bg-rose-700 text-white  cursor-pointer w-24 text-center font-semibold px-2 py-2 rounded-md  hover:text-slate-300   transition-all duration-150">
                SignUp
              </li>
            </Link>
            )}

          {token && (
            <button
             onClick={onLogOutHandler}
             className="sm:ml-0 -ml-1 bg-rose-700 text-white  cursor-pointer w-24 text-center font-semibold px-2 py-2 rounded-md  hover:text-slate-300   transition-all duration-150">
              LogOut
            </button>
            )}
        </ul>
        <button
          onClick={() => setNavbarOpen(!navbarOpen)}
          className="sm:hidden flex items-center sm:mt-0 mt-2"
        >
          {navbarOpen ? (
            <RxCross2 className="text-white text-3xl" />
          ) : (
            <IoIosMenu className="text-white text-3xl" />
          )}
        </button>
      </div>
    </div>
  );
};

export default Navbar;

import React, { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { IoIosMenu } from "react-icons/io";
import { RxCross2 } from "react-icons/rx";
import { motion } from "framer-motion";
import { useStoreContext } from "../contextApi/ContextApi";

const Navbar = () => {
  const navigate = useNavigate();
  const { token, setToken } = useStoreContext();
  const path = useLocation().pathname;
  const [navbarOpen, setNavbarOpen] = useState(false);

  const onLogOutHandler = () => {
    setToken(null);
    localStorage.removeItem("JWT_TOKEN");
    navigate("/login");
  };

  const navItems = [
    { path: "/", label: "Home" },
    { path: "/about", label: "About" },
    { path: "/scanner", label: "URL Scanner" },
    ...(token ? [{ path: "/dashboard", label: "Dashboard" }] : []),
  ];

  return (
    <header className="sticky top-0 z-50 border-b border-white/10 bg-slate-900/65 backdrop-blur-xl">
      <div className="lg:px-14 sm:px-8 px-4 h-16 w-full flex justify-between items-center">
        <Link to="/" className="relative z-20">
          <h1 className="font-bold text-3xl text-white italic">Linklytics</h1>
        </Link>

        <ul
          className={`sm:static absolute left-0 top-16 sm:w-auto w-full sm:h-auto sm:bg-transparent bg-slate-900/95 sm:backdrop-blur-none backdrop-blur-xl
            sm:flex sm:flex-row flex-col sm:items-center gap-2 sm:gap-6 px-4 sm:px-0 transition-all duration-300 border-b sm:border-0 border-white/10
            ${navbarOpen ? "max-h-96 py-3" : "max-h-0 py-0 overflow-hidden sm:max-h-none"}`}
        >
          {navItems.map((item) => {
            const active = path === item.path;
            return (
              <li key={item.path} className="relative py-1">
                <Link
                  to={item.path}
                  className={`text-sm font-medium transition-colors duration-200 ${
                    active ? "text-white" : "text-slate-300 hover:text-white"
                  }`}
                  onClick={() => setNavbarOpen(false)}
                >
                  {item.label}
                </Link>
                {active && (
                  <motion.span
                    layoutId="nav-underline"
                    className="absolute -bottom-1 left-0 h-0.5 w-full bg-gradient-to-r from-blue-400 to-purple-500"
                  />
                )}
              </li>
            );
          })}

          {!token && (
            <li className="sm:ml-2">
              <Link to="/register" onClick={() => setNavbarOpen(false)}>
                <motion.span
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                  className="inline-block btn-gradient text-sm"
                >
                  Sign Up
                </motion.span>
              </Link>
            </li>
          )}

          {token && (
            <li className="sm:ml-2">
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={onLogOutHandler}
                className="bg-rose-600/90 text-white text-sm font-semibold rounded-xl px-4 py-2 shadow-lg shadow-rose-700/30"
              >
                Log Out
              </motion.button>
            </li>
          )}
        </ul>

        <button
          onClick={() => setNavbarOpen((prev) => !prev)}
          className="sm:hidden flex items-center"
          aria-label="Toggle navigation"
        >
          {navbarOpen ? (
            <RxCross2 className="text-white text-3xl" />
          ) : (
            <IoIosMenu className="text-white text-3xl" />
          )}
        </button>
      </div>
    </header>
  );
};

export default Navbar;

package com.url.shortener.service;

import org.springframework.stereotype.Service;

import java.net.HttpURLConnection;
import java.net.URI;
import java.net.URL;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

@Service
public class UrlResolverService {

    private static final int MAX_REDIRECTS = 5;
    private static final int CONNECT_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 5000;

    public ResolvedResult resolveUrl(String inputUrl) {
        String current = normalize(inputUrl);
        if (current.isBlank()) {
            return new ResolvedResult(current, List.of());
        }

        List<String> chain = new ArrayList<>();
        chain.add(current);
        Set<String> visited = new HashSet<>();
        visited.add(current);

        for (int i = 0; i < MAX_REDIRECTS; i++) {
            String location = readLocationHeader(current);
            if (location == null || location.isBlank()) {
                return new ResolvedResult(current, chain);
            }

            String next = normalize(toAbsoluteUrl(current, location));
            if (next.isBlank()) {
                return new ResolvedResult(current, chain);
            }

            chain.add(next);
            if (!visited.add(next)) {
                return new ResolvedResult(next, chain);
            }

            current = next;
        }

        return new ResolvedResult(current, chain);
    }

    public String resolveFinalUrl(String inputUrl) {
        return resolveUrl(inputUrl).finalUrl();
    }

    private String readLocationHeader(String url) {
        HttpURLConnection connection = null;
        try {
            connection = (HttpURLConnection) new URL(url).openConnection();
            connection.setRequestMethod("HEAD");
            connection.setConnectTimeout(CONNECT_TIMEOUT_MS);
            connection.setReadTimeout(READ_TIMEOUT_MS);
            connection.setInstanceFollowRedirects(false);
            connection.setRequestProperty("User-Agent", "UrlScanner/1.0");

            int status = connection.getResponseCode();
            if (isRedirectStatus(status)) {
                return connection.getHeaderField("Location");
            }
            return null;
        } catch (Exception ex) {
            // Fail safe: scanner should continue even if resolver cannot resolve.
            return null;
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
    }

    private boolean isRedirectStatus(int status) {
        return status == HttpURLConnection.HTTP_MOVED_PERM
                || status == HttpURLConnection.HTTP_MOVED_TEMP
                || status == HttpURLConnection.HTTP_SEE_OTHER
                || status == 307
                || status == 308;
    }

    private String toAbsoluteUrl(String baseUrl, String location) {
        try {
            URI base = URI.create(baseUrl);
            URI next = base.resolve(location);
            return next.toString();
        } catch (Exception ex) {
            return location;
        }
    }

    private String normalize(String value) {
        if (value == null) {
            return "";
        }

        String normalized = value.trim();
        if (!normalized.isBlank()
                && !normalized.toLowerCase().startsWith("http://")
                && !normalized.toLowerCase().startsWith("https://")) {
            normalized = "https://" + normalized;
        }

        if (normalized.endsWith("/") && normalized.length() > "https://".length()) {
            normalized = normalized.substring(0, normalized.length() - 1);
        }
        return normalized;
    }

    public record ResolvedResult(String finalUrl, List<String> chain) {
    }
}

package com.url.shortener.service;

import com.url.shortener.exception.InvalidUrlException;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.HttpStatusCode;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.net.URI;
import java.util.ArrayList;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;

@Service
@RequiredArgsConstructor
public class UrlResolverService {

    @Value("${url.scan.redirect.max-depth:10}")
    private int maxRedirects;

    private final RestTemplate scannerRestTemplate;
    private final UrlNormalizationService urlNormalizationService;
    private final SsrfProtectionService ssrfProtectionService;
    private final HttpRetryService retryService;

    public ResolvedResult resolveUrl(String inputUrl) {
        UrlNormalizationService.NormalizedUrl normalized = urlNormalizationService.normalizeAndValidate(inputUrl);
        URI current = normalized.uri();

        List<String> chain = new ArrayList<>();
        Set<String> visited = new LinkedHashSet<>();
        chain.add(current.toString());
        visited.add(current.toString());

        for (int hop = 0; hop < Math.max(1, maxRedirects); hop++) {
            ssrfProtectionService.assertPublicDestination(current);
            String location = readLocationHeader(current);
            if (location == null || location.isBlank()) {
                return new ResolvedResult(current.toString(), chain, false, false);
            }

            URI next = current.resolve(location);
            UrlNormalizationService.NormalizedUrl nextNormalized = urlNormalizationService.normalizeAndValidate(next.toString());
            current = nextNormalized.uri();

            ssrfProtectionService.assertPublicDestination(current);

            String canonical = current.toString();
            chain.add(canonical);
            if (!visited.add(canonical)) {
                return new ResolvedResult(canonical, chain, true, false);
            }
        }

        return new ResolvedResult(current.toString(), chain, false, true);
    }

    private String readLocationHeader(URI current) {
        HttpHeaders headers = new HttpHeaders();
        headers.set("User-Agent", "UrlScanner/2.0");
        HttpEntity<Void> request = new HttpEntity<>(headers);

        ResponseEntity<String> response = executeRequest(current, HttpMethod.HEAD, request);
        if (isRedirect(response.getStatusCode())) {
            return response.getHeaders().getFirst(HttpHeaders.LOCATION);
        }

        if (response.getStatusCode().value() == 405 || response.getStatusCode().value() == 501) {
            ResponseEntity<String> fallback = executeRequest(current, HttpMethod.GET, request);
            if (isRedirect(fallback.getStatusCode())) {
                return fallback.getHeaders().getFirst(HttpHeaders.LOCATION);
            }
        }

        return null;
    }

    private ResponseEntity<String> executeRequest(URI uri, HttpMethod method, HttpEntity<Void> request) {
        try {
            return retryService.execute(() -> scannerRestTemplate.exchange(uri, method, request, String.class));
        } catch (Exception ex) {
            return ResponseEntity.ok().build();
        }
    }

    private boolean isRedirect(HttpStatusCode statusCode) {
        int status = statusCode.value();
        return status == 301 || status == 302 || status == 303 || status == 307 || status == 308;
    }

    public record ResolvedResult(String finalUrl,
                                 List<String> chain,
                                 boolean loopDetected,
                                 boolean maxDepthReached) {
    }
}

package com.url.shortener.service;

import com.url.shortener.dtos.UrlScanResponse;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class UrlScanCacheService {

    private final Map<String, CacheEntry> cache = new ConcurrentHashMap<>();

    @Value("${url.scan.cache.enabled:true}")
    private boolean cacheEnabled;

    @Value("${url.scan.cache.ttl-seconds:600}")
    private long ttlSeconds;

    @Value("${url.scan.cache.max-size:500}")
    private int maxSize;

    public UrlScanResponse get(String key) {
        if (!cacheEnabled || key == null || key.isBlank()) {
            return null;
        }

        CacheEntry entry = cache.get(key);
        if (entry == null) {
            return null;
        }

        if (isExpired(entry)) {
            cache.remove(key);
            return null;
        }

        return copyResponse(entry.response());
    }

    public void put(String key, UrlScanResponse response) {
        if (!cacheEnabled || key == null || key.isBlank() || response == null || ttlSeconds <= 0) {
            return;
        }

        if (cache.size() >= Math.max(maxSize, 1)) {
            evictOneEntry();
        }

        long expiresAt = System.currentTimeMillis() + (ttlSeconds * 1000);
        cache.put(key, new CacheEntry(copyResponse(response), expiresAt));
    }

    public void clear() {
        cache.clear();
    }

    private boolean isExpired(CacheEntry entry) {
        return System.currentTimeMillis() > entry.expiresAtEpochMillis();
    }

    private void evictOneEntry() {
        cache.keySet().stream().findFirst().ifPresent(cache::remove);
    }

    private UrlScanResponse copyResponse(UrlScanResponse source) {
        return new UrlScanResponse(
                source.getStatus(),
                source.getMessage(),
                source.getScannedUrl(),
                source.getFinalScore(),
                source.getBreakdown() == null ? new LinkedHashMap<>() : new LinkedHashMap<>(source.getBreakdown()),
                source.getCategoryLabels() == null ? new LinkedHashMap<>() : new LinkedHashMap<>(source.getCategoryLabels()),
                source.getChecksPerformed() == null ? new ArrayList<>() : new ArrayList<>(source.getChecksPerformed()),
                source.getReasons() == null ? new ArrayList<>() : new ArrayList<>(source.getReasons()),
                source.getRedirectChain() == null ? new ArrayList<>() : new ArrayList<>(source.getRedirectChain()),
                source.getFinalUrl(),
                source.getContactedDomains() == null ? new ArrayList<>() : new ArrayList<>(source.getContactedDomains()),
                source.getScriptCount(),
                source.getPageTitle(),
                source.getScreenshotUrl()
        );
    }

    private record CacheEntry(UrlScanResponse response, long expiresAtEpochMillis) {
    }
}

package com.url.shortener.service;

import com.github.benmanes.caffeine.cache.Cache;
import com.github.benmanes.caffeine.cache.Caffeine;
import com.url.shortener.dtos.UrlScanResponse;
import jakarta.annotation.PostConstruct;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.concurrent.TimeUnit;

@Service
public class UrlScanCacheService {

    @Value("${url.scan.cache.enabled:true}")
    private boolean cacheEnabled;

    @Value("${url.scan.cache.ttl-seconds:600}")
    private long ttlSeconds;

    @Value("${url.scan.cache.max-size:500}")
    private int maxSize;

    private Cache<String, UrlScanResponse> cache;

    @PostConstruct
    void init() {
        cache = Caffeine.newBuilder()
                .maximumSize(Math.max(1, maxSize))
                .expireAfterWrite(Math.max(1, ttlSeconds), TimeUnit.SECONDS)
                .build();
    }

    public UrlScanResponse get(String key) {
        if (!cacheEnabled || key == null || key.isBlank()) {
            return null;
        }
        UrlScanResponse response = cache.getIfPresent(key);
        return response == null ? null : copyResponse(response);
    }

    public void put(String key, UrlScanResponse response) {
        if (!cacheEnabled || key == null || key.isBlank() || response == null) {
            return;
        }
        cache.put(key, copyResponse(response));
    }

    public void clear() {
        cache.invalidateAll();
    }

    private UrlScanResponse copyResponse(UrlScanResponse source) {
        UrlScanResponse copied = new UrlScanResponse(
                source.getStatus(),
                source.getMessage(),
                source.getScannedUrl(),
                source.getFinalScore(),
                source.getBreakdown() == null ? new LinkedHashMap<>() : new LinkedHashMap<>(source.getBreakdown()),
                source.getCategoryLabels() == null ? new LinkedHashMap<>() : new LinkedHashMap<>(source.getCategoryLabels()),
                source.getChecksPerformed() == null ? new ArrayList<>() : new ArrayList<>(source.getChecksPerformed()),
                source.getReasons() == null ? new ArrayList<>() : new ArrayList<>(source.getReasons()),
                source.getRedirectChain() == null ? new ArrayList<>() : new ArrayList<>(source.getRedirectChain()),
                source.getFinalUrl(),
                source.getContactedDomains() == null ? new ArrayList<>() : new ArrayList<>(source.getContactedDomains()),
                source.getScriptCount(),
                source.getPageTitle(),
                source.getScreenshotUrl()
        );
        copied.setTotalRequests(source.getTotalRequests());
        return copied;
    }
}

package com.url.shortener.dtos;

import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

@Data
@NoArgsConstructor
@AllArgsConstructor
public class UrlScanResponse {
    private String status;
    private String message;
    private String scannedUrl;
    private int finalScore;
    private Map<String, Integer> breakdown;
    private Map<String, String> categoryLabels;
    private List<String> checksPerformed;
    private List<String> reasons;

    // urlscan behavior insights
    private List<String> redirectChain;
    private String finalUrl;
    private List<String> contactedDomains;
    private int scriptCount;
    private String pageTitle;
    private String screenshotUrl;

    // Backward-compatible constructor used by older code paths.
    public UrlScanResponse(String status, String message, String scannedUrl, int riskScore, List<String> reasons) {
        this.status = status;
        this.message = message;
        this.scannedUrl = scannedUrl;
        this.finalScore = riskScore;
        this.breakdown = new LinkedHashMap<>();
        this.categoryLabels = new LinkedHashMap<>();
        this.checksPerformed = new ArrayList<>();
        this.reasons = reasons == null ? new ArrayList<>() : reasons;
        this.redirectChain = new ArrayList<>();
        this.finalUrl = scannedUrl;
        this.contactedDomains = new ArrayList<>();
        this.scriptCount = 0;
        this.pageTitle = "";
        this.screenshotUrl = "";
    }

    // Compatibility accessor for older usages that still read riskScore.
    public int getRiskScore() {
        return finalScore;
    }
}

package com.url.shortener.dtos;

import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

@Data
@NoArgsConstructor
@AllArgsConstructor
public class UrlScanResponse {
    private String status;
    private String message;
    private String scannedUrl;
    private int finalScore;
    private Map<String, Integer> breakdown;
    private Map<String, String> categoryLabels;
    private List<String> checksPerformed;
    private List<String> reasons;

    // urlscan behavior insights
    private List<String> redirectChain;
    private String finalUrl;
    private List<String> contactedDomains;
    private int scriptCount;
    private int totalRequests;
    private String pageTitle;
    private String screenshotUrl;

    // Compatibility constructor used by existing service/controller/tests.
    public UrlScanResponse(
            String status,
            String message,
            String scannedUrl,
            int finalScore,
            Map<String, Integer> breakdown,
            Map<String, String> categoryLabels,
            List<String> checksPerformed,
            List<String> reasons,
            List<String> redirectChain,
            String finalUrl,
            List<String> contactedDomains,
            int scriptCount,
            String pageTitle,
            String screenshotUrl
    ) {
        this.status = status;
        this.message = message;
        this.scannedUrl = scannedUrl;
        this.finalScore = finalScore;
        this.breakdown = breakdown == null ? new LinkedHashMap<>() : breakdown;
        this.categoryLabels = categoryLabels == null ? new LinkedHashMap<>() : categoryLabels;
        this.checksPerformed = checksPerformed == null ? new ArrayList<>() : checksPerformed;
        this.reasons = reasons == null ? new ArrayList<>() : reasons;
        this.redirectChain = redirectChain == null ? new ArrayList<>() : redirectChain;
        this.finalUrl = finalUrl;
        this.contactedDomains = contactedDomains == null ? new ArrayList<>() : contactedDomains;
        this.scriptCount = scriptCount;
        this.totalRequests = 0;
        this.pageTitle = pageTitle;
        this.screenshotUrl = screenshotUrl;
    }

    // Backward-compatible constructor used by older code paths.
    public UrlScanResponse(String status, String message, String scannedUrl, int riskScore, List<String> reasons) {
        this.status = status;
        this.message = message;
        this.scannedUrl = scannedUrl;
        this.finalScore = riskScore;
        this.breakdown = new LinkedHashMap<>();
        this.categoryLabels = new LinkedHashMap<>();
        this.checksPerformed = new ArrayList<>();
        this.reasons = reasons == null ? new ArrayList<>() : reasons;
        this.redirectChain = new ArrayList<>();
        this.finalUrl = scannedUrl;
        this.contactedDomains = new ArrayList<>();
        this.scriptCount = 0;
        this.totalRequests = 0;
        this.pageTitle = "";
        this.screenshotUrl = "";
    }

    // Compatibility accessor for older usages that still read riskScore.
    public int getRiskScore() {
        return finalScore;
    }

    // UI alias so frontend can read `domains` without changing backend internals.
    public List<String> getDomains() {
        return contactedDomains;
    }

    public void setDomains(List<String> domains) {
        this.contactedDomains = domains == null ? new ArrayList<>() : domains;
    }
}

package com.url.shortener.service;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.url.shortener.dtos.UrlScanAsyncStatusResponse;
import com.url.shortener.dtos.UrlScanHistoryResponse;
import com.url.shortener.dtos.UrlScanResponse;
import lombok.RequiredArgsConstructor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.server.ResponseStatusException;
import org.springframework.web.util.UriComponentsBuilder;

import java.net.HttpURLConnection;
import java.net.URI;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.Base64;
import java.util.LinkedHashMap;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

@Service
@RequiredArgsConstructor
public class UrlScannerService {

    private static final Logger log = LoggerFactory.getLogger(UrlScannerService.class);

    @Value("${google.safe-browsing.api-key:}")
    private String safeBrowsingApiKey;

    @Value("${google.safe-browsing.url}")
    private String safeBrowsingUrl;

    @Value("${virustotal.api-key:}")
    private String virusTotalApiKey;

    @Value("${virustotal.url:https://www.virustotal.com/api/v3/urls}")
    private String virusTotalUrl;

    @Value("${urlscan.api-key:}")
    private String urlscanApiKey;

    @Value("${urlscan.submit-url:https://urlscan.io/api/v1/scan/}")
    private String urlscanSubmitUrl;

    @Value("${urlscan.result-url-template:https://urlscan.io/api/v1/result/%s/}")
    private String urlscanResultUrlTemplate;

    @Value("${urlscan.poll.max-attempts:6}")
    private int urlscanPollMaxAttempts;

    @Value("${urlscan.poll.delay-ms:1500}")
    private long urlscanPollDelayMs;

    @Value("${url.scan.max-length:120}")
    private int maxUrlLength;

    @Value("${url.scan.suspicious-tlds:xyz,tk,top}")
    private String suspiciousTldsCsv;

    @Value("${url.scan.piracy-keywords:movie,download,watch free,torrent}")
    private String piracyKeywordsCsv;

    @Value("${url.scan.ad-keywords:ads,click,redirect,banner,track,tracker}")
    private String adKeywordsCsv;

    @Value("${url.scan.trusted-domains:facebook.com,google.com,twitter.com}")
    private String trustedDomainsCsv;

    @Value("${url.scan.async.timeout-ms:20000}")
    private long asyncTimeoutMs;

    @Value("${url.scan.async.job-retention-seconds:900}")
    private long asyncJobRetentionSeconds;

    @Value("${url.scan.async.max-jobs:200}")
    private int maxAsyncJobs;

    private final ObjectMapper objectMapper;

    private final Map<String, AsyncScanJob> asyncJobs = new ConcurrentHashMap<>();
    private final ExecutorService asyncExecutor = Executors.newCachedThreadPool();
    private final ScheduledExecutorService asyncScheduler = Executors.newSingleThreadScheduledExecutor();

    public UrlScanResponse scanUrl(String url) {
        return scanUrlInternal(url, false);
    }

    private UrlScanResponse scanUrlInternal(String url, boolean forceUrlscan) {
        String normalizedUrl = normalizeUrl(url);
        if (normalizedUrl.isBlank()) {
            return buildErrorResponse("INVALID_REQUEST", "URL is required", null,
                    List.of("Please provide a valid URL in request body"));
        }

        try {
            int malwareScore = 0;
            int phishingScore = 0;
            int piracyScore = 0;
            int spamScore = 0;
            int redirectScore = 0;
            int domainScore = 0;

            List<String> reasons = new ArrayList<>();
            Map<String, Object> apiResults = new LinkedHashMap<>();

            String inputDomain = extractDomain(normalizedUrl);
            boolean trustedDomain = isTrustedDomain(inputDomain);
            boolean suspiciousDomain = isSuspiciousDomain(inputDomain);

            RedirectTrace redirectTrace = traceRedirectChain(normalizedUrl);
            String scannedUrl = redirectTrace.finalUrl;
            UrlscanBehavior behavior = UrlscanBehavior.empty(scannedUrl);
            behavior.redirectChain = new ArrayList<>(redirectTrace.chain);
            behavior.finalUrl = scannedUrl;

            if (redirectTrace.chain.size() > 1) {
                reasons.add("URL redirects through multiple steps");
            }
            if (isKnownShortener(inputDomain)) {
                reasons.add("Shortened URL detected");
            }
            if (redirectTrace.chain.size() > 2) {
                redirectScore += 25;
                reasons.add("Multiple redirects detected");
            }
            if (hasDomainChangeAcrossRedirects(redirectTrace.chain)) {
                redirectScore += 20;
                reasons.add("Domain changed across redirects");
            }

            // STEP 1/2: Always call Google Safe Browsing and treat it as highest authority.
            GoogleSafeBrowsingResult gsb = checkGoogleSafeBrowsing(scannedUrl);
            if (gsb.externalError) {
                apiResults.put("googleSafeBrowsing", "UNAVAILABLE");
                reasons.add("Google Safe Browsing unavailable");
            } else if (gsb.hasAnyThreat()) {
                apiResults.put("googleSafeBrowsing", "THREAT DETECTED");
                if (gsb.malwareThreat) {
                    malwareScore += 100;
                }
                if (gsb.phishingThreat) {
                    phishingScore += 90;
                }
                reasons.add("Google Safe Browsing detected threat");
            } else {
                apiResults.put("googleSafeBrowsing", "CLEAN");
                reasons.add("No malware detected by Google Safe Browsing");
            }

            // STEP 3: urlscan behavior engine, called conditionally.
            boolean shouldCallUrlscan = forceUrlscan || redirectTrace.chain.size() > 1 || suspiciousDomain;
            if (shouldCallUrlscan) {
                UrlscanBehavior urlscanBehavior = scanWithUrlScan(scannedUrl);
                if (urlscanBehavior.externalError) {
                    spamScore += 5;
                    reasons.add("Partial analysis due to urlscan failure");
                    apiResults.put("urlscan", Map.of(
                            "status", "FAILED",
                            "scriptCount", 0,
                            "domains", 0
                    ));
                } else {
                    behavior = urlscanBehavior;
                    scannedUrl = normalizeUrl(behavior.finalUrl);

                    if (behavior.redirectChain.size() > 2) {
                        redirectScore += 25;
                        reasons.add("Multiple redirects detected");
                    }
                    if (hasDomainChangeAcrossRedirects(behavior.redirectChain)) {
                        redirectScore += 20;
                        reasons.add("Domain changed across redirects");
                    }

                    if (behavior.scriptCount > 20) {
                        spamScore += 30;
                        reasons.add("High script activity detected");
                    }
                    if (behavior.contactedDomains.size() > 15) {
                        spamScore += 20;
                        reasons.add("High number of contacted domains");
                    }
                    if (containsAdTrackerKeyword(behavior.contactedDomains)) {
                        spamScore += 30;
                        reasons.add("Tracking/ad network behavior detected");
                    }
                    if (containsPiracyTitle(behavior.pageTitle)) {
                        piracyScore += 50;
                        reasons.add("Piracy-related content identified");
                    }

                    apiResults.put("urlscan", Map.of(
                            "status", "SUCCESS",
                            "scriptCount", behavior.scriptCount,
                            "domains", behavior.contactedDomains.size()
                    ));
                }
            } else {
                apiResults.put("urlscan", Map.of(
                        "status", "SKIPPED",
                        "scriptCount", 0,
                        "domains", 0
                ));
            }

            // Light domain heuristics only.
            String finalDomain = extractDomain(scannedUrl);
            if (isSuspiciousTld(getTld(finalDomain))) {
                domainScore += 20;
                reasons.add("Suspicious TLD detected");
            }
            if (hasSuspiciousDigitSubstitution(getPrimaryDomain(finalDomain))) {
                domainScore += 30;
                reasons.add("Possible typo domain pattern detected");
            }

            // Mild spam heuristics for URL structure.
            if (scannedUrl.length() > maxUrlLength) {
                spamScore += 20;
                reasons.add("Long URL structure detected");
            }
            if (countQueryParams(scannedUrl) >= 4) {
                spamScore += 20;
                reasons.add("Many query parameters detected");
            }
            if (!getMatchedKeywords(scannedUrl, adKeywordsCsv).isEmpty()) {
                spamScore += 20;
                reasons.add("Ad/tracker URL patterns detected");
            }

            // STEP 5: VirusTotal only if GSB clean and behavior indicates risk.
            boolean safeBrowsingClean = !gsb.hasAnyThreat();
            boolean behaviorSignal = redirectScore > 0 || spamScore > 20;
            boolean shouldCallVirusTotal = safeBrowsingClean && behaviorSignal && !trustedDomain;
            if (shouldCallVirusTotal) {
                VirusTotalStats vt = checkVirusTotal(scannedUrl);
                if (vt.malicious > 0) {
                    malwareScore += 80;
                }
                if (vt.suspicious > 0) {
                    malwareScore += 40;
                }
                if (vt.malicious > 0 || vt.suspicious > 0) {
                    reasons.add("VirusTotal flagged " + (vt.malicious + vt.suspicious) + " engines");
                }
                apiResults.put("virusTotal", Map.of(
                        "status", vt.externalError ? "FAILED" : "SUCCESS",
                        "malicious", vt.malicious,
                        "suspicious", vt.suspicious
                ));
            } else {
                apiResults.put("virusTotal", Map.of(
                        "status", trustedDomain ? "SKIPPED_TRUSTED" : "SKIPPED",
                        "malicious", 0,
                        "suspicious", 0
                ));
            }

            // STEP 6/10: trusted-domain protection.
            if (trustedDomain) {
                spamScore = Math.max(0, spamScore - 10);
                redirectScore = Math.max(0, redirectScore - 10);
            }

            Map<String, Integer> breakdown = new LinkedHashMap<>();
            breakdown.put("malware", malwareScore);
            breakdown.put("phishing", phishingScore);
            breakdown.put("piracy", piracyScore);
            breakdown.put("spam", spamScore);
            breakdown.put("redirectRisk", redirectScore);
            breakdown.put("domainRisk", domainScore);

            Map<String, String> categoryLabels = new LinkedHashMap<>();
            categoryLabels.put("malware", toCategoryLabel(malwareScore));
            categoryLabels.put("phishing", toCategoryLabel(phishingScore));
            categoryLabels.put("piracy", toCategoryLabel(piracyScore));
            categoryLabels.put("spam", toCategoryLabel(spamScore));
            categoryLabels.put("redirectRisk", toCategoryLabel(redirectScore));
            categoryLabels.put("domainRisk", toCategoryLabel(domainScore));

            // STEP 8: finalScore is UI-only.
            int finalScore = calculateFinalScore(malwareScore, phishingScore, piracyScore, spamScore, redirectScore, domainScore);

            // STEP 1/10: status is category-threshold based, not finalScore.
            String status = determineStatus(malwareScore, phishingScore, piracyScore, spamScore, trustedDomain, gsb);
            String message = determineMessage(status, malwareScore, phishingScore, piracyScore, spamScore);

            List<String> finalReasons = dedupeReasons(reasons);
            if (finalReasons.isEmpty()) {
                finalReasons.add("No malware detected by Google Safe Browsing");
            }

            return new UrlScanResponse(
                    status,
                    message,
                    scannedUrl,
                    finalScore,
                    breakdown,
                    categoryLabels,
                    apiResults,
                    finalReasons,
                    behavior.redirectChain,
                    scannedUrl,
                    behavior.contactedDomains,
                    behavior.scriptCount,
                    behavior.pageTitle,
                    behavior.screenshotUrl
            );
        } catch (Exception ex) {
            log.error("Scan failed for URL: {}", normalizedUrl, ex);
            return buildErrorResponse(
                    "SCAN_ERROR",
                    "Scan failed due to internal or external provider issue.",
                    normalizedUrl,
                    List.of("Unable to complete scan right now. Please try again.")
            );
        }
    }

    private UrlScanResponse buildErrorResponse(String status, String message, String scannedUrl, List<String> reasons) {
        return new UrlScanResponse(
                status,
                message,
                scannedUrl,
                0,
                new LinkedHashMap<>(),
                new LinkedHashMap<>(),
                new LinkedHashMap<>(),
                reasons,
                new ArrayList<>(),
                scannedUrl,
                new ArrayList<>(),
                0,
                "",
                ""
        );
    }

    // Google Safe Browsing API integration (primary signal)
    private GoogleSafeBrowsingResult checkGoogleSafeBrowsing(String url) {
        if (safeBrowsingApiKey == null || safeBrowsingApiKey.isBlank()) {
            return GoogleSafeBrowsingResult.unavailable();
        }

        try {
            URI requestUri = UriComponentsBuilder
                    .fromUriString(safeBrowsingUrl)
                    .queryParam("key", safeBrowsingApiKey)
                    .build(true)
                    .toUri();

            HttpHeaders headers = new HttpHeaders();
            headers.setContentType(MediaType.APPLICATION_JSON);
            HttpEntity<Map<String, Object>> requestEntity = new HttpEntity<>(buildSafeBrowsingPayload(url), headers);

            RestTemplate restTemplate = new RestTemplate();
            ResponseEntity<String> response = restTemplate.postForEntity(requestUri, requestEntity, String.class);
            return parseSafeBrowsingResult(response.getBody());
        } catch (Exception ex) {
            log.error("Google Safe Browsing failed for URL: {}", url, ex);
            return GoogleSafeBrowsingResult.unavailable();
        }
    }

    private GoogleSafeBrowsingResult parseSafeBrowsingResult(String body) throws Exception {
        if (body == null || body.isBlank()) {
            return new GoogleSafeBrowsingResult(false, false, false);
        }

        JsonNode root = objectMapper.readTree(body);
        JsonNode matches = root.path("matches");
        boolean malware = false;
        boolean phishing = false;

        if (matches.isArray()) {
            for (JsonNode match : matches) {
                String threatType = match.path("threatType").asText("");
                if ("MALWARE".equalsIgnoreCase(threatType)) {
                    malware = true;
                }
                if ("SOCIAL_ENGINEERING".equalsIgnoreCase(threatType)) {
                    phishing = true;
                }
            }
        }

        return new GoogleSafeBrowsingResult(malware, phishing, false);
    }

    // Controlled VirusTotal integration (secondary signal)
    private VirusTotalStats checkVirusTotal(String url) {
        if (virusTotalApiKey == null || virusTotalApiKey.isBlank()) {
            return VirusTotalStats.unavailable();
        }

        try {
            URI lookupUri = UriComponentsBuilder
                    .fromUriString(virusTotalUrl)
                    .pathSegment(encodeUrlForVirusTotal(url))
                    .build(true)
                    .toUri();

            HttpHeaders headers = new HttpHeaders();
            headers.add("x-apikey", virusTotalApiKey);
            HttpEntity<Void> entity = new HttpEntity<>(headers);

            RestTemplate restTemplate = new RestTemplate();
            ResponseEntity<String> response = restTemplate.exchange(lookupUri, HttpMethod.GET, entity, String.class);
            String body = response.getBody();

            if (body == null || body.isBlank()) {
                return VirusTotalStats.unavailable();
            }

            JsonNode root = objectMapper.readTree(body);
            JsonNode stats = root.path("data").path("attributes").path("last_analysis_stats");
            return VirusTotalStats.of(stats.path("malicious").asInt(0), stats.path("suspicious").asInt(0));
        } catch (HttpClientErrorException.NotFound ex) {
            return VirusTotalStats.of(0, 0);
        } catch (Exception ex) {
            log.error("VirusTotal failed for URL: {}", url, ex);
            return VirusTotalStats.unavailable();
        }
    }

    // urlscan behavior integration
    private UrlscanBehavior scanWithUrlScan(String url) {
        if (urlscanApiKey == null || urlscanApiKey.isBlank()) {
            return UrlscanBehavior.externalFailure(url);
        }

        try {
            String uuid = submitUrlscanJob(url);
            if (uuid == null || uuid.isBlank()) {
                return UrlscanBehavior.externalFailure(url);
            }
            return pollUrlscanResult(uuid, url);
        } catch (Exception ex) {
            log.error("urlscan submit failed for URL: {}", url, ex);
            return UrlscanBehavior.externalFailure(url);
        }
    }

    private String submitUrlscanJob(String url) throws Exception {
        RestTemplate restTemplate = new RestTemplate();

        Map<String, Object> payload = new LinkedHashMap<>();
        payload.put("url", url);
        payload.put("visibility", "public");

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        headers.add("API-Key", urlscanApiKey);

        HttpEntity<Map<String, Object>> request = new HttpEntity<>(payload, headers);
        ResponseEntity<String> response = restTemplate.postForEntity(urlscanSubmitUrl, request, String.class);
        String body = response.getBody();

        if (body == null || body.isBlank()) {
            return null;
        }

        JsonNode root = objectMapper.readTree(body);
        return root.path("uuid").asText(null);
    }

    private UrlscanBehavior pollUrlscanResult(String uuid, String originalUrl) {
        RestTemplate restTemplate = new RestTemplate();

        for (int attempt = 1; attempt <= urlscanPollMaxAttempts; attempt++) {
            try {
                String resultUrl = String.format(urlscanResultUrlTemplate, uuid);

                HttpHeaders headers = new HttpHeaders();
                headers.add("API-Key", urlscanApiKey);
                HttpEntity<Void> entity = new HttpEntity<>(headers);

                ResponseEntity<String> response = restTemplate.exchange(resultUrl, HttpMethod.GET, entity, String.class);
                String body = response.getBody();
                if (body != null && !body.isBlank()) {
                    JsonNode root = objectMapper.readTree(body);
                    return parseUrlscanResult(root, originalUrl);
                }
            } catch (HttpClientErrorException.NotFound ex) {
                // Result not ready yet.
            } catch (Exception ex) {
                log.error("urlscan poll failed for UUID: {}", uuid, ex);
                return UrlscanBehavior.externalFailure(originalUrl);
            }

            try {
                Thread.sleep(urlscanPollDelayMs);
            } catch (InterruptedException ex) {
                Thread.currentThread().interrupt();
                return UrlscanBehavior.externalFailure(originalUrl);
            }
        }

        return UrlscanBehavior.externalFailure(originalUrl);
    }

    private UrlscanBehavior parseUrlscanResult(JsonNode root, String originalUrl) {
        UrlscanBehavior behavior = UrlscanBehavior.empty(originalUrl);

        String finalUrl = root.path("page").path("url").asText("");
        if (finalUrl.isBlank()) {
            finalUrl = root.path("task").path("url").asText(originalUrl);
        }
        behavior.finalUrl = normalizeUrl(finalUrl);

        JsonNode redirectsNode = root.path("lists").path("redirects");
        behavior.redirectChain = new ArrayList<>();
        if (redirectsNode.isArray()) {
            for (JsonNode node : redirectsNode) {
                String redirect = node.asText("").trim();
                if (!redirect.isBlank()) {
                    behavior.redirectChain.add(normalizeUrl(redirect));
                }
            }
        }
        if (behavior.redirectChain.isEmpty()) {
            behavior.redirectChain.add(normalizeUrl(originalUrl));
            if (!behavior.finalUrl.equalsIgnoreCase(normalizeUrl(originalUrl))) {
                behavior.redirectChain.add(behavior.finalUrl);
            }
        }

        JsonNode domainsNode = root.path("lists").path("domains");
        behavior.contactedDomains = new ArrayList<>();
        if (domainsNode.isArray()) {
            for (JsonNode node : domainsNode) {
                String domain = node.asText("").trim().toLowerCase();
                if (!domain.isBlank()) {
                    behavior.contactedDomains.add(domain);
                }
            }
        }

        JsonNode scriptsNode = root.path("lists").path("scripts");
        behavior.scriptCount = scriptsNode.isArray() ? scriptsNode.size() : 0;
        behavior.pageTitle = root.path("page").path("title").asText("");
        behavior.screenshotUrl = root.path("task").path("screenshotURL").asText("");
        if (behavior.screenshotUrl.isBlank()) {
            behavior.screenshotUrl = root.path("page").path("screenshot").asText("");
        }

        return behavior;
    }

    // Manual redirect tracking with HttpURLConnection.
    private RedirectTrace traceRedirectChain(String inputUrl) {
        List<String> chain = new ArrayList<>();
        String current = normalizeUrl(inputUrl);
        chain.add(current);

        try {
            for (int i = 0; i < 5; i++) {
                HttpURLConnection connection = (HttpURLConnection) new URL(current).openConnection();
                connection.setRequestMethod("HEAD");
                connection.setConnectTimeout(5000);
                connection.setReadTimeout(5000);
                connection.setInstanceFollowRedirects(false);
                connection.setRequestProperty("User-Agent", "UrlScanner/1.0");

                int status = connection.getResponseCode();
                if (!isRedirectStatus(status)) {
                    connection.disconnect();
                    return new RedirectTrace(current, chain, false);
                }

                String location = connection.getHeaderField("Location");
                connection.disconnect();

                if (location == null || location.isBlank()) {
                    return new RedirectTrace(current, chain, false);
                }

                URI nextUri = URI.create(current).resolve(location);
                String next = normalizeUrl(nextUri.toString());
                if (chain.contains(next)) {
                    return new RedirectTrace(next, chain, true);
                }

                chain.add(next);
                current = next;
            }

            return new RedirectTrace(current, chain, false);
        } catch (Exception ex) {
            log.error("Redirect tracking failed for URL: {}", inputUrl, ex);
            return new RedirectTrace(normalizeUrl(inputUrl), chain, true);
        }
    }

    private boolean isRedirectStatus(int statusCode) {
        return statusCode == HttpURLConnection.HTTP_MOVED_PERM
                || statusCode == HttpURLConnection.HTTP_MOVED_TEMP
                || statusCode == HttpURLConnection.HTTP_SEE_OTHER
                || statusCode == 307
                || statusCode == 308;
    }

    private Map<String, Object> buildSafeBrowsingPayload(String url) {
        Map<String, Object> client = new LinkedHashMap<>();
        client.put("clientId", "url-shortener");
        client.put("clientVersion", "1.0");

        Map<String, Object> threatEntry = new LinkedHashMap<>();
        threatEntry.put("url", url);

        Map<String, Object> threatInfo = new LinkedHashMap<>();
        threatInfo.put("threatTypes", List.of("MALWARE", "SOCIAL_ENGINEERING"));
        threatInfo.put("platformTypes", List.of("ANY_PLATFORM"));
        threatInfo.put("threatEntryTypes", List.of("URL"));
        threatInfo.put("threatEntries", List.of(threatEntry));

        Map<String, Object> payload = new LinkedHashMap<>();
        payload.put("client", client);
        payload.put("threatInfo", threatInfo);
        return payload;
    }

    private String normalizeUrl(String input) {
        if (input == null) {
            return "";
        }

        String normalized = input.trim();
        if (!normalized.isBlank()
                && !normalized.toLowerCase().startsWith("http://")
                && !normalized.toLowerCase().startsWith("https://")) {
            normalized = "https://" + normalized;
        }

        if (normalized.endsWith("/") && normalized.length() > "https://".length()) {
            normalized = normalized.substring(0, normalized.length() - 1);
        }

        return normalized;
    }

    private boolean isTrustedDomain(String domain) {
        if (domain == null || domain.isBlank()) {
            return false;
        }

        for (String trusted : trustedDomainsCsv.split(",")) {
            String clean = trusted.trim().toLowerCase();
            if (!clean.isBlank() && (domain.equals(clean) || domain.endsWith("." + clean))) {
                return true;
            }
        }
        return false;
    }

    private boolean isKnownShortener(String domain) {
        if (domain == null || domain.isBlank()) {
            return false;
        }
        return Set.of("bit.ly", "t.co", "tinyurl.com", "goo.gl", "ow.ly", "is.gd").contains(domain);
    }

    private boolean isSuspiciousDomain(String domain) {
        if (domain == null || domain.isBlank()) {
            return false;
        }
        return isSuspiciousTld(getTld(domain)) || hasSuspiciousDigitSubstitution(getPrimaryDomain(domain));
    }

    private boolean hasDomainChangeAcrossRedirects(List<String> redirectChain) {
        if (redirectChain == null || redirectChain.size() < 2) {
            return false;
        }

        Set<String> domains = new LinkedHashSet<>();
        for (String url : redirectChain) {
            String domain = extractDomain(url);
            if (!domain.isBlank()) {
                domains.add(domain);
            }
        }
        return domains.size() > 1;
    }

    private boolean containsAdTrackerKeyword(List<String> domains) {
        if (domains == null || domains.isEmpty()) {
            return false;
        }

        for (String domain : domains) {
            String lower = domain.toLowerCase();
            for (String keyword : List.of("ad", "ads", "track", "tracker", "click", "banner", "redirect")) {
                if (lower.contains(keyword)) {
                    return true;
                }
            }
        }
        return false;
    }

    private boolean containsPiracyTitle(String title) {
        if (title == null || title.isBlank()) {
            return false;
        }

        String lower = title.toLowerCase();
        for (String keyword : List.of("download", "watch", "free", "movie")) {
            if (lower.contains(keyword)) {
                return true;
            }
        }
        return false;
    }

    private List<String> getMatchedKeywords(String source, String csvKeywords) {
        List<String> matches = new ArrayList<>();
        String lowerSource = source == null ? "" : source.toLowerCase();

        for (String raw : csvKeywords.split(",")) {
            String keyword = raw.trim().toLowerCase();
            if (!keyword.isBlank() && lowerSource.contains(keyword)) {
                matches.add(keyword);
            }
        }
        return matches;
    }

    private int countQueryParams(String url) {
        int questionIndex = url.indexOf('?');
        if (questionIndex < 0 || questionIndex >= url.length() - 1) {
            return 0;
        }

        int count = 1;
        for (char ch : url.substring(questionIndex + 1).toCharArray()) {
            if (ch == '&') {
                count++;
            }
        }
        return count;
    }

    private String extractDomain(String url) {
        try {
            URL parsed = new URL(url);
            return parsed.getHost() == null ? "" : parsed.getHost().toLowerCase();
        } catch (Exception ex) {
            return "";
        }
    }

    private String getPrimaryDomain(String domain) {
        if (domain == null || domain.isBlank()) {
            return "";
        }
        String[] parts = domain.split("\\.");
        return parts.length >= 2 ? parts[parts.length - 2] : domain;
    }

    private String getTld(String domain) {
        if (domain == null || domain.isBlank() || !domain.contains(".")) {
            return "";
        }
        String[] parts = domain.split("\\.");
        return parts[parts.length - 1].toLowerCase();
    }

    private boolean isSuspiciousTld(String tld) {
        if (tld == null || tld.isBlank()) {
            return false;
        }

        for (String raw : suspiciousTldsCsv.split(",")) {
            if (tld.equals(raw.trim().toLowerCase())) {
                return true;
            }
        }
        return false;
    }

    private boolean hasSuspiciousDigitSubstitution(String primaryDomain) {
        if (primaryDomain == null || primaryDomain.isBlank()) {
            return false;
        }

        boolean hasLetter = false;
        boolean hasDigit = false;
        for (char ch : primaryDomain.toCharArray()) {
            if (Character.isLetter(ch)) {
                hasLetter = true;
            }
            if (Character.isDigit(ch)) {
                hasDigit = true;
            }
        }
        return hasLetter && hasDigit;
    }

    private int calculateFinalScore(int malware, int phishing, int piracy, int spam, int redirectRisk, int domainRisk) {
        double weighted = malware
                + phishing
                + (piracy * 0.6)
                + (spam * 0.4)
                + redirectRisk
                + domainRisk;

        return Math.max(0, Math.min(100, (int) Math.round(weighted)));
    }

    private String determineStatus(int malware, int phishing, int piracy, int spam, boolean trustedDomain, GoogleSafeBrowsingResult gsb) {
        if (malware >= 70) {
            return "DANGEROUS";
        }
        if (phishing >= 70) {
            return "DANGEROUS";
        }
        if (piracy >= 60) {
            return "SUSPICIOUS";
        }
        if (spam >= 60) {
            return "SUSPICIOUS";
        }

        if (trustedDomain && !gsb.hasAnyThreat()) {
            return "SAFE";
        }

        return "SAFE";
    }

    private String determineMessage(String status, int malware, int phishing, int piracy, int spam) {
        if ("DANGEROUS".equals(status) && malware >= 70) {
            return "Malware risk confirmed by high-confidence signals";
        }
        if ("DANGEROUS".equals(status) && phishing >= 70) {
            return "Phishing risk confirmed by high-confidence signals";
        }
        if ("SUSPICIOUS".equals(status) && piracy >= 60) {
            return "Piracy-related behavior identified";
        }
        if ("SUSPICIOUS".equals(status) && spam >= 60) {
            return "Spam/ad-heavy behavior identified";
        }
        return "No malware detected";
    }

    private String toCategoryLabel(int score) {
        if (score >= 70) {
            return "HIGH";
        }
        if (score >= 30) {
            return "MEDIUM";
        }
        return "SAFE";
    }

    private String encodeUrlForVirusTotal(String url) {
        return Base64.getUrlEncoder().withoutPadding().encodeToString(url.getBytes(StandardCharsets.UTF_8));
    }

    private List<String> dedupeReasons(List<String> reasons) {
        return new ArrayList<>(new LinkedHashSet<>(reasons));
    }

    public String submitAsyncScan(String url) {
        cleanupExpiredAsyncJobs();
        long pendingJobs = asyncJobs.values().stream().filter(AsyncScanJob::isPending).count();
        if (pendingJobs >= maxAsyncJobs) {
            throw new ResponseStatusException(HttpStatus.TOO_MANY_REQUESTS, "Too many async scan jobs");
        }

        String normalized = normalizeUrl(url);
        String jobId = UUID.randomUUID().toString();
        AsyncScanJob job = new AsyncScanJob(jobId);
        asyncJobs.put(jobId, job);

        CompletableFuture
                .supplyAsync(() -> scanUrlInternal(normalized, true), asyncExecutor)
                .whenComplete((response, throwable) -> {
                    if (throwable != null) {
                        completeWithFallback(jobId, normalized);
                    } else {
                        completeJob(jobId, response);
                    }
                });

        asyncScheduler.schedule(() -> completeWithFallback(jobId, normalized), asyncTimeoutMs, TimeUnit.MILLISECONDS);
        return jobId;
    }

    public UrlScanAsyncStatusResponse getAsyncScanStatus(String jobId) {
        cleanupExpiredAsyncJobs();
        AsyncScanJob job = asyncJobs.get(jobId);
        if (job == null) {
            throw new ResponseStatusException(HttpStatus.NOT_FOUND, "Async scan job not found");
        }
        return new UrlScanAsyncStatusResponse(job.jobId, job.status, job.result, job.errorMessage);
    }

    private void completeWithFallback(String jobId, String url) {
        AsyncScanJob job = asyncJobs.get(jobId);
        if (job == null || !job.isPending()) {
            return;
        }

        UrlScanResponse fallback = scanUrlInternal(url, false);
        List<String> reasons = fallback.getReasons() == null ? new ArrayList<>() : new ArrayList<>(fallback.getReasons());
        reasons.add("Fallback mode activated due to async failure");
        fallback.setReasons(dedupeReasons(reasons));
        completeJob(jobId, fallback);
    }

    private void completeJob(String jobId, UrlScanResponse response) {
        AsyncScanJob job = asyncJobs.get(jobId);
        if (job == null) {
            return;
        }

        synchronized (job) {
            if (!job.isPending()) {
                return;
            }
            job.status = "COMPLETED";
            job.result = response;
            job.errorMessage = null;
            job.completedAtMs = System.currentTimeMillis();
        }
    }

    public void runScheduledAsyncCleanup() {
        cleanupExpiredAsyncJobs();
    }

    private void cleanupExpiredAsyncJobs() {
        long retentionMs = Math.max(0, asyncJobRetentionSeconds) * 1000;
        long now = System.currentTimeMillis();

        asyncJobs.entrySet().removeIf(entry -> {
            AsyncScanJob job = entry.getValue();
            if (job.isPending()) {
                return false;
            }
            if (retentionMs == 0) {
                return true;
            }
            return job.completedAtMs > 0 && (now - job.completedAtMs) >= retentionMs;
        });
    }

    public List<UrlScanHistoryResponse> getScanHistory(int limit, String status) {
        return List.of();
    }

    public UrlScanHistoryResponse getScanHistoryById(Long id) {
        return new UrlScanHistoryResponse(
                id,
                null,
                "NOT_FOUND",
                "Scan history is currently disabled",
                0,
                List.of(),
                null
        );
    }

    public void clearScanCache() {
        log.info("Scan cache clear requested, but cache is currently disabled");
    }

    private static class RedirectTrace {
        private final String finalUrl;
        private final List<String> chain;
        private final boolean hadError;

        private RedirectTrace(String finalUrl, List<String> chain, boolean hadError) {
            this.finalUrl = finalUrl;
            this.chain = chain;
            this.hadError = hadError;
        }
    }

    private static class GoogleSafeBrowsingResult {
        private final boolean malwareThreat;
        private final boolean phishingThreat;
        private final boolean externalError;

        private GoogleSafeBrowsingResult(boolean malwareThreat, boolean phishingThreat, boolean externalError) {
            this.malwareThreat = malwareThreat;
            this.phishingThreat = phishingThreat;
            this.externalError = externalError;
        }

        private static GoogleSafeBrowsingResult unavailable() {
            return new GoogleSafeBrowsingResult(false, false, true);
        }

        private boolean hasAnyThreat() {
            return malwareThreat || phishingThreat;
        }
    }

    private static class VirusTotalStats {
        private final int malicious;
        private final int suspicious;
        private final boolean externalError;

        private VirusTotalStats(int malicious, int suspicious, boolean externalError) {
            this.malicious = malicious;
            this.suspicious = suspicious;
            this.externalError = externalError;
        }

        private static VirusTotalStats of(int malicious, int suspicious) {
            return new VirusTotalStats(malicious, suspicious, false);
        }

        private static VirusTotalStats unavailable() {
            return new VirusTotalStats(0, 0, true);
        }
    }

    private static class UrlscanBehavior {
        private List<String> redirectChain;
        private String finalUrl;
        private List<String> contactedDomains;
        private int scriptCount;
        private String pageTitle;
        private String screenshotUrl;
        private boolean externalError;

        private static UrlscanBehavior empty(String baseUrl) {
            UrlscanBehavior behavior = new UrlscanBehavior();
            behavior.redirectChain = new ArrayList<>();
            behavior.redirectChain.add(baseUrl);
            behavior.finalUrl = baseUrl;
            behavior.contactedDomains = new ArrayList<>();
            behavior.scriptCount = 0;
            behavior.pageTitle = "";
            behavior.screenshotUrl = "";
            behavior.externalError = false;
            return behavior;
        }

        private static UrlscanBehavior externalFailure(String baseUrl) {
            UrlscanBehavior behavior = empty(baseUrl);
            behavior.externalError = true;
            return behavior;
        }
    }

    private static class AsyncScanJob {
        private final String jobId;
        private volatile String status;
        private volatile UrlScanResponse result;
        private volatile String errorMessage;
        private volatile long completedAtMs;

        private AsyncScanJob(String jobId) {
            this.jobId = jobId;
            this.status = "PENDING";
            this.result = null;
            this.errorMessage = null;
            this.completedAtMs = 0;
        }

        private boolean isPending() {
            return "PENDING".equals(this.status);
        }
    }
}

package com.url.shortener.service;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.url.shortener.dtos.UrlScanAsyncStatusResponse;
import com.url.shortener.dtos.UrlScanHistoryResponse;
import com.url.shortener.dtos.UrlScanResponse;
import lombok.RequiredArgsConstructor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.server.ResponseStatusException;
import org.springframework.web.util.UriComponentsBuilder;

import java.net.HttpURLConnection;
import java.net.URI;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.Base64;
import java.util.LinkedHashMap;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

@Service
@RequiredArgsConstructor
public class UrlScannerService {

    private static final Logger log = LoggerFactory.getLogger(UrlScannerService.class);

    @Value("${google.safe-browsing.api-key:}")
    private String safeBrowsingApiKey;

    @Value("${google.safe-browsing.url}")
    private String safeBrowsingUrl;

    @Value("${virustotal.api-key:}")
    private String virusTotalApiKey;

    @Value("${virustotal.url:https://www.virustotal.com/api/v3/urls}")
    private String virusTotalUrl;

    @Value("${urlscan.api-key:}")
    private String urlscanApiKey;

    @Value("${urlscan.submit-url:https://urlscan.io/api/v1/scan/}")
    private String urlscanSubmitUrl;

    @Value("${urlscan.result-url-template:https://urlscan.io/api/v1/result/%s/}")
    private String urlscanResultUrlTemplate;

    @Value("${urlscan.poll.max-attempts:6}")
    private int urlscanPollMaxAttempts;

    @Value("${urlscan.poll.delay-ms:1500}")
    private long urlscanPollDelayMs;

    @Value("${url.scan.max-length:120}")
    private int maxUrlLength;

    @Value("${url.scan.suspicious-tlds:xyz,tk,top}")
    private String suspiciousTldsCsv;

    @Value("${url.scan.piracy-keywords:movie,download,watch free,torrent}")
    private String piracyKeywordsCsv;

    @Value("${url.scan.ad-keywords:ads,click,redirect,banner,track,tracker}")
    private String adKeywordsCsv;

    @Value("${url.scan.trusted-domains:facebook.com,google.com,twitter.com}")
    private String trustedDomainsCsv;

    @Value("${url.scan.async.timeout-ms:20000}")
    private long asyncTimeoutMs;

    @Value("${url.scan.async.job-retention-seconds:900}")
    private long asyncJobRetentionSeconds;

    @Value("${url.scan.async.max-jobs:200}")
    private int maxAsyncJobs;

    private final ObjectMapper objectMapper;

    private final Map<String, AsyncScanJob> asyncJobs = new ConcurrentHashMap<>();
    private final ExecutorService asyncExecutor = Executors.newCachedThreadPool();
    private final ScheduledExecutorService asyncScheduler = Executors.newSingleThreadScheduledExecutor();

    public UrlScanResponse scanUrl(String url) {
        return scanUrlInternal(url, false);
    }

    private UrlScanResponse scanUrlInternal(String url, boolean forceUrlscan) {
        String normalizedUrl = normalizeUrl(url);
        if (normalizedUrl.isBlank()) {
            return buildErrorResponse("INVALID_REQUEST", "URL is required", null,
                    List.of("Please provide a valid URL in request body"));
        }

        try {
            int malwareScore = 0;
            int phishingScore = 0;
            int piracyScore = 0;
            int spamScore = 0;
            int redirectScore = 0;
            int domainScore = 0;

            List<String> reasons = new ArrayList<>();
            Map<String, Object> apiResults = new LinkedHashMap<>();

            String inputDomain = extractDomain(normalizedUrl);
            boolean trustedDomain = isTrustedDomain(inputDomain);

            // Force redirect resolution before any scanning.
            RedirectTrace redirectTrace = traceRedirectChain(normalizedUrl);
            String finalUrl = redirectTrace.finalUrl;
            String finalDomain = extractDomain(finalUrl);
            boolean suspiciousDomain = isSuspiciousDomain(finalDomain);

            UrlscanBehavior behavior = UrlscanBehavior.empty(finalUrl);
            behavior.redirectChain = new ArrayList<>(redirectTrace.chain);
            behavior.finalUrl = finalUrl;

            if (redirectTrace.chain.size() > 1) {
                redirectScore += 20;
                reasons.add("URL redirects detected");
            }
            if (isKnownShortener(inputDomain)) {
                reasons.add("Shortened URL detected");
            }
            if (hasDomainChangeAcrossRedirects(redirectTrace.chain)) {
                redirectScore += 20;
                reasons.add("Domain changed across redirects");
            }

            // STEP 1/2: Always call Google Safe Browsing and treat it as highest authority.
            GoogleSafeBrowsingResult gsb = checkGoogleSafeBrowsing(finalUrl);
            if (gsb.externalError) {
                apiResults.put("googleSafeBrowsing", "UNAVAILABLE");
                reasons.add("Google Safe Browsing unavailable");
            } else if (gsb.hasAnyThreat()) {
                apiResults.put("googleSafeBrowsing", "THREAT DETECTED");
                if (gsb.malwareThreat) {
                    malwareScore += 100;
                }
                if (gsb.phishingThreat) {
                    phishingScore += 90;
                }
                reasons.add("Google Safe Browsing detected threat");
            } else {
                apiResults.put("googleSafeBrowsing", "CLEAN");
                reasons.add("No malware detected by Google Safe Browsing");
            }

            // STEP 3: urlscan behavior engine, called conditionally.
            boolean shouldCallUrlscan = forceUrlscan || redirectTrace.chain.size() > 1 || suspiciousDomain;
            if (shouldCallUrlscan) {
                UrlscanBehavior urlscanBehavior = scanWithUrlScan(finalUrl);
                if (urlscanBehavior.externalError) {
                    spamScore += 5;
                    reasons.add("Partial analysis due to urlscan failure");
                    apiResults.put("urlscan", "FAILED");
                } else {
                    behavior = urlscanBehavior;
                    finalUrl = normalizeUrl(behavior.finalUrl);
                    finalDomain = extractDomain(finalUrl);

                    if (behavior.redirectChain.size() > 1) {
                        redirectScore += 20;
                        reasons.add("URL redirects detected");
                    }
                    if (hasDomainChangeAcrossRedirects(behavior.redirectChain)) {
                        redirectScore += 20;
                        reasons.add("Domain changed across redirects");
                    }

                    if (behavior.scriptCount > 20) {
                        spamScore += 30;
                        reasons.add("High script activity detected");
                    }
                    if (behavior.contactedDomains.size() > 15) {
                        spamScore += 20;
                        reasons.add("High number of contacted domains");
                    }

                    apiResults.put("urlscan", "SUCCESS (scripts=" + behavior.scriptCount + ", domains=" + behavior.contactedDomains.size() + ")");
                }
            } else {
                apiResults.put("urlscan", "SKIPPED");
            }

            // Piracy detection from final domain, final URL and page title.
            if (containsPiracySignals(finalUrl, finalDomain, behavior.pageTitle)) {
                piracyScore += 70;
                reasons.add("Piracy-related domain detected");
            }

            if (isSuspiciousTld(getTld(finalDomain))) {
                domainScore += 20;
                reasons.add("Suspicious TLD detected");
            }
            if (hasSuspiciousDigitSubstitution(getPrimaryDomain(finalDomain))) {
                domainScore += 30;
                reasons.add("Possible typo domain pattern detected");
            }

            if (finalUrl.length() > maxUrlLength) {
                spamScore += 20;
                reasons.add("Long URL structure detected");
            }
            if (countQueryParams(finalUrl) >= 4) {
                spamScore += 20;
                reasons.add("Many query parameters detected");
            }
            if (!getMatchedKeywords(finalUrl, adKeywordsCsv).isEmpty()) {
                spamScore += 20;
                reasons.add("Ad/tracker URL patterns detected");
            }

            boolean safeBrowsingClean = !gsb.hasAnyThreat();
            boolean behaviorSignal = redirectScore > 0 || spamScore > 20;
            boolean shouldCallVirusTotal = safeBrowsingClean && behaviorSignal && !trustedDomain;
            if (shouldCallVirusTotal) {
                VirusTotalStats vt = checkVirusTotal(finalUrl);
                if (vt.malicious > 0) {
                    malwareScore += 80;
                }
                if (vt.suspicious > 0) {
                    malwareScore += 40;
                }
                int totalThreats = Math.max(0, vt.malicious) + Math.max(0, vt.suspicious);
                apiResults.put("virusTotal", vt.externalError ? "FAILED" : (totalThreats + " threats"));
                if (totalThreats > 0) {
                    reasons.add("VirusTotal flagged " + totalThreats + " engines");
                }
            } else {
                apiResults.put("virusTotal", trustedDomain ? "SKIPPED (TRUSTED DOMAIN)" : "SKIPPED");
            }

            if (trustedDomain) {
                spamScore = Math.max(0, spamScore - 10);
                redirectScore = Math.max(0, redirectScore - 10);
            }

            Map<String, Integer> breakdown = new LinkedHashMap<>();
            breakdown.put("malware", malwareScore);
            breakdown.put("phishing", phishingScore);
            breakdown.put("piracy", piracyScore);
            breakdown.put("spam", spamScore);
            breakdown.put("redirectRisk", redirectScore);
            breakdown.put("domainRisk", domainScore);

            Map<String, String> categoryLabels = new LinkedHashMap<>();
            categoryLabels.put("malware", toCategoryLabel(malwareScore));
            categoryLabels.put("phishing", toCategoryLabel(phishingScore));
            categoryLabels.put("piracy", toCategoryLabel(piracyScore));
            categoryLabels.put("spam", toCategoryLabel(spamScore));
            categoryLabels.put("redirectRisk", toCategoryLabel(redirectScore));
            categoryLabels.put("domainRisk", toCategoryLabel(domainScore));

            // STEP 8: finalScore is UI-only.
            int finalScore = calculateFinalScore(malwareScore, phishingScore, piracyScore, spamScore, redirectScore, domainScore);

            // STEP 1/10: status is category-threshold based, not finalScore.
            String status = determineStatus(malwareScore, phishingScore, piracyScore, spamScore, trustedDomain, gsb);
            String message = determineMessage(status, malwareScore, phishingScore, piracyScore, spamScore);

            // Never return SAFE if final URL has piracy keyword signals.
            if ("SAFE".equals(status) && containsPiracySignals(finalUrl, finalDomain, behavior.pageTitle)) {
                status = "SUSPICIOUS";
            }

            List<String> finalReasons = dedupeReasons(reasons);
            if (finalReasons.isEmpty()) {
                finalReasons.add("No malware detected by Google Safe Browsing");
            }

            return new UrlScanResponse(
                    status,
                    message,
                    finalUrl,
                    finalScore,
                    breakdown,
                    categoryLabels,
                    apiResults,
                    finalReasons,
                    behavior.redirectChain,
                    finalUrl,
                    behavior.contactedDomains,
                    behavior.scriptCount,
                    behavior.pageTitle,
                    behavior.screenshotUrl
            );
        } catch (Exception ex) {
            log.error("Scan failed for URL: {}", normalizedUrl, ex);
            return buildErrorResponse(
                    "SCAN_ERROR",
                    "Scan failed due to internal or external provider issue.",
                    normalizedUrl,
                    List.of("Unable to complete scan right now. Please try again.")
            );
        }
    }

    private UrlScanResponse buildErrorResponse(String status, String message, String scannedUrl, List<String> reasons) {
        return new UrlScanResponse(
                status,
                message,
                scannedUrl,
                0,
                new LinkedHashMap<>(),
                new LinkedHashMap<>(),
                new LinkedHashMap<>(),
                reasons,
                new ArrayList<>(),
                scannedUrl,
                new ArrayList<>(),
                0,
                "",
                ""
        );
    }

    // Google Safe Browsing API integration (primary signal)
    private GoogleSafeBrowsingResult checkGoogleSafeBrowsing(String url) {
        if (safeBrowsingApiKey == null || safeBrowsingApiKey.isBlank()) {
            return GoogleSafeBrowsingResult.unavailable();
        }

        try {
            URI requestUri = UriComponentsBuilder
                    .fromUriString(safeBrowsingUrl)
                    .queryParam("key", safeBrowsingApiKey)
                    .build(true)
                    .toUri();

            HttpHeaders headers = new HttpHeaders();
            headers.setContentType(MediaType.APPLICATION_JSON);
            HttpEntity<Map<String, Object>> requestEntity = new HttpEntity<>(buildSafeBrowsingPayload(url), headers);

            RestTemplate restTemplate = new RestTemplate();
            ResponseEntity<String> response = restTemplate.postForEntity(requestUri, requestEntity, String.class);
            return parseSafeBrowsingResult(response.getBody());
        } catch (Exception ex) {
            log.error("Google Safe Browsing failed for URL: {}", url, ex);
            return GoogleSafeBrowsingResult.unavailable();
        }
    }

    private GoogleSafeBrowsingResult parseSafeBrowsingResult(String body) throws Exception {
        if (body == null || body.isBlank()) {
            return new GoogleSafeBrowsingResult(false, false, false);
        }

        JsonNode root = objectMapper.readTree(body);
        JsonNode matches = root.path("matches");
        boolean malware = false;
        boolean phishing = false;

        if (matches.isArray()) {
            for (JsonNode match : matches) {
                String threatType = match.path("threatType").asText("");
                if ("MALWARE".equalsIgnoreCase(threatType)) {
                    malware = true;
                }
                if ("SOCIAL_ENGINEERING".equalsIgnoreCase(threatType)) {
                    phishing = true;
                }
            }
        }

        return new GoogleSafeBrowsingResult(malware, phishing, false);
    }

    // Controlled VirusTotal integration (secondary signal)
    private VirusTotalStats checkVirusTotal(String url) {
        if (virusTotalApiKey == null || virusTotalApiKey.isBlank()) {
            return VirusTotalStats.unavailable();
        }

        try {
            URI lookupUri = UriComponentsBuilder
                    .fromUriString(virusTotalUrl)
                    .pathSegment(encodeUrlForVirusTotal(url))
                    .build(true)
                    .toUri();

            HttpHeaders headers = new HttpHeaders();
            headers.add("x-apikey", virusTotalApiKey);
            HttpEntity<Void> entity = new HttpEntity<>(headers);

            RestTemplate restTemplate = new RestTemplate();
            ResponseEntity<String> response = restTemplate.exchange(lookupUri, HttpMethod.GET, entity, String.class);
            String body = response.getBody();

            if (body == null || body.isBlank()) {
                return VirusTotalStats.unavailable();
            }

            JsonNode root = objectMapper.readTree(body);
            JsonNode stats = root.path("data").path("attributes").path("last_analysis_stats");
            return VirusTotalStats.of(stats.path("malicious").asInt(0), stats.path("suspicious").asInt(0));
        } catch (HttpClientErrorException.NotFound ex) {
            return VirusTotalStats.of(0, 0);
        } catch (Exception ex) {
            log.error("VirusTotal failed for URL: {}", url, ex);
            return VirusTotalStats.unavailable();
        }
    }

    // urlscan behavior integration
    private UrlscanBehavior scanWithUrlScan(String url) {
        if (urlscanApiKey == null || urlscanApiKey.isBlank()) {
            return UrlscanBehavior.externalFailure(url);
        }

        try {
            String uuid = submitUrlscanJob(url);
            if (uuid == null || uuid.isBlank()) {
                return UrlscanBehavior.externalFailure(url);
            }
            return pollUrlscanResult(uuid, url);
        } catch (Exception ex) {
            log.error("urlscan submit failed for URL: {}", url, ex);
            return UrlscanBehavior.externalFailure(url);
        }
    }

    private String submitUrlscanJob(String url) throws Exception {
        RestTemplate restTemplate = new RestTemplate();

        Map<String, Object> payload = new LinkedHashMap<>();
        payload.put("url", url);
        payload.put("visibility", "public");

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        headers.add("API-Key", urlscanApiKey);

        HttpEntity<Map<String, Object>> request = new HttpEntity<>(payload, headers);
        ResponseEntity<String> response = restTemplate.postForEntity(urlscanSubmitUrl, request, String.class);
        String body = response.getBody();

        if (body == null || body.isBlank()) {
            return null;
        }

        JsonNode root = objectMapper.readTree(body);
        return root.path("uuid").asText(null);
    }

    private UrlscanBehavior pollUrlscanResult(String uuid, String originalUrl) {
        RestTemplate restTemplate = new RestTemplate();

        for (int attempt = 1; attempt <= urlscanPollMaxAttempts; attempt++) {
            try {
                String resultUrl = String.format(urlscanResultUrlTemplate, uuid);

                HttpHeaders headers = new HttpHeaders();
                headers.add("API-Key", urlscanApiKey);
                HttpEntity<Void> entity = new HttpEntity<>(headers);

                ResponseEntity<String> response = restTemplate.exchange(resultUrl, HttpMethod.GET, entity, String.class);
                String body = response.getBody();
                if (body != null && !body.isBlank()) {
                    JsonNode root = objectMapper.readTree(body);
                    return parseUrlscanResult(root, originalUrl);
                }
            } catch (HttpClientErrorException.NotFound ex) {
                // Result not ready yet.
            } catch (Exception ex) {
                log.error("urlscan poll failed for UUID: {}", uuid, ex);
                return UrlscanBehavior.externalFailure(originalUrl);
            }

            try {
                Thread.sleep(urlscanPollDelayMs);
            } catch (InterruptedException ex) {
                Thread.currentThread().interrupt();
                return UrlscanBehavior.externalFailure(originalUrl);
            }
        }

        return UrlscanBehavior.externalFailure(originalUrl);
    }

    private UrlscanBehavior parseUrlscanResult(JsonNode root, String originalUrl) {
        UrlscanBehavior behavior = UrlscanBehavior.empty(originalUrl);

        String finalUrl = root.path("page").path("url").asText("");
        if (finalUrl.isBlank()) {
            finalUrl = root.path("task").path("url").asText(originalUrl);
        }
        behavior.finalUrl = normalizeUrl(finalUrl);

        JsonNode redirectsNode = root.path("lists").path("redirects");
        behavior.redirectChain = new ArrayList<>();
        if (redirectsNode.isArray()) {
            for (JsonNode node : redirectsNode) {
                String redirect = node.asText("").trim();
                if (!redirect.isBlank()) {
                    behavior.redirectChain.add(normalizeUrl(redirect));
                }
            }
        }
        if (behavior.redirectChain.isEmpty()) {
            behavior.redirectChain.add(normalizeUrl(originalUrl));
            if (!behavior.finalUrl.equalsIgnoreCase(normalizeUrl(originalUrl))) {
                behavior.redirectChain.add(behavior.finalUrl);
            }
        }

        JsonNode domainsNode = root.path("lists").path("domains");
        behavior.contactedDomains = new ArrayList<>();
        if (domainsNode.isArray()) {
            for (JsonNode node : domainsNode) {
                String domain = node.asText("").trim().toLowerCase();
                if (!domain.isBlank()) {
                    behavior.contactedDomains.add(domain);
                }
            }
        }

        JsonNode scriptsNode = root.path("lists").path("scripts");
        behavior.scriptCount = scriptsNode.isArray() ? scriptsNode.size() : 0;
        behavior.pageTitle = root.path("page").path("title").asText("");
        behavior.screenshotUrl = root.path("task").path("screenshotURL").asText("");
        if (behavior.screenshotUrl.isBlank()) {
            behavior.screenshotUrl = root.path("page").path("screenshot").asText("");
        }

        return behavior;
    }

    // Manual redirect tracking with HttpURLConnection.
    private RedirectTrace traceRedirectChain(String inputUrl) {
        List<String> chain = new ArrayList<>();
        String current = normalizeUrl(inputUrl);
        chain.add(current);

        try {
            for (int i = 0; i < 5; i++) {
                HttpURLConnection connection = (HttpURLConnection) new URL(current).openConnection();
                connection.setRequestMethod("HEAD");
                connection.setConnectTimeout(5000);
                connection.setReadTimeout(5000);
                connection.setInstanceFollowRedirects(false);
                connection.setRequestProperty("User-Agent", "UrlScanner/1.0");

                int status = connection.getResponseCode();
                if (!isRedirectStatus(status)) {
                    connection.disconnect();
                    return new RedirectTrace(current, chain, false);
                }

                String location = connection.getHeaderField("Location");
                connection.disconnect();

                if (location == null || location.isBlank()) {
                    return new RedirectTrace(current, chain, false);
                }

                URI nextUri = URI.create(current).resolve(location);
                String next = normalizeUrl(nextUri.toString());
                if (chain.contains(next)) {
                    return new RedirectTrace(next, chain, true);
                }

                chain.add(next);
                current = next;
            }

            return new RedirectTrace(current, chain, false);
        } catch (Exception ex) {
            log.error("Redirect tracking failed for URL: {}", inputUrl, ex);
            return new RedirectTrace(normalizeUrl(inputUrl), chain, true);
        }
    }

    private boolean isRedirectStatus(int statusCode) {
        return statusCode == HttpURLConnection.HTTP_MOVED_PERM
                || statusCode == HttpURLConnection.HTTP_MOVED_TEMP
                || statusCode == HttpURLConnection.HTTP_SEE_OTHER
                || statusCode == 307
                || statusCode == 308;
    }

    private Map<String, Object> buildSafeBrowsingPayload(String url) {
        Map<String, Object> client = new LinkedHashMap<>();
        client.put("clientId", "url-shortener");
        client.put("clientVersion", "1.0");

        Map<String, Object> threatEntry = new LinkedHashMap<>();
        threatEntry.put("url", url);

        Map<String, Object> threatInfo = new LinkedHashMap<>();
        threatInfo.put("threatTypes", List.of("MALWARE", "SOCIAL_ENGINEERING"));
        threatInfo.put("platformTypes", List.of("ANY_PLATFORM"));
        threatInfo.put("threatEntryTypes", List.of("URL"));
        threatInfo.put("threatEntries", List.of(threatEntry));

        Map<String, Object> payload = new LinkedHashMap<>();
        payload.put("client", client);
        payload.put("threatInfo", threatInfo);
        return payload;
    }

    private String normalizeUrl(String input) {
        if (input == null) {
            return "";
        }

        String normalized = input.trim();
        if (!normalized.isBlank()
                && !normalized.toLowerCase().startsWith("http://")
                && !normalized.toLowerCase().startsWith("https://")) {
            normalized = "https://" + normalized;
        }

        if (normalized.endsWith("/") && normalized.length() > "https://".length()) {
            normalized = normalized.substring(0, normalized.length() - 1);
        }

        return normalized;
    }

    private boolean isTrustedDomain(String domain) {
        if (domain == null || domain.isBlank()) {
            return false;
        }

        for (String trusted : trustedDomainsCsv.split(",")) {
            String clean = trusted.trim().toLowerCase();
            if (!clean.isBlank() && (domain.equals(clean) || domain.endsWith("." + clean))) {
                return true;
            }
        }
        return false;
    }

    private boolean isKnownShortener(String domain) {
        if (domain == null || domain.isBlank()) {
            return false;
        }
        return Set.of("bit.ly", "t.co", "tinyurl.com", "goo.gl", "ow.ly", "is.gd").contains(domain);
    }

    private boolean isSuspiciousDomain(String domain) {
        if (domain == null || domain.isBlank()) {
            return false;
        }
        return isSuspiciousTld(getTld(domain)) || hasSuspiciousDigitSubstitution(getPrimaryDomain(domain));
    }

    private boolean hasDomainChangeAcrossRedirects(List<String> redirectChain) {
        if (redirectChain == null || redirectChain.size() < 2) {
            return false;
        }

        Set<String> domains = new LinkedHashSet<>();
        for (String url : redirectChain) {
            String domain = extractDomain(url);
            if (!domain.isBlank()) {
                domains.add(domain);
            }
        }
        return domains.size() > 1;
    }

    private boolean containsAdTrackerKeyword(List<String> domains) {
        if (domains == null || domains.isEmpty()) {
            return false;
        }

        for (String domain : domains) {
            String lower = domain.toLowerCase();
            for (String keyword : List.of("ad", "ads", "track", "tracker", "click", "banner", "redirect")) {
                if (lower.contains(keyword)) {
                    return true;
                }
            }
        }
        return false;
    }

    private boolean containsPiracyTitle(String title) {
        if (title == null || title.isBlank()) {
            return false;
        }

        String lower = title.toLowerCase();
        for (String keyword : List.of("download", "watch", "free", "movie")) {
            if (lower.contains(keyword)) {
                return true;
            }
        }
        return false;
    }

    private List<String> getMatchedKeywords(String source, String csvKeywords) {
        List<String> matches = new ArrayList<>();
        String lowerSource = source == null ? "" : source.toLowerCase();

        for (String raw : csvKeywords.split(",")) {
            String keyword = raw.trim().toLowerCase();
            if (!keyword.isBlank() && lowerSource.contains(keyword)) {
                matches.add(keyword);
            }
        }
        return matches;
    }

    private int countQueryParams(String url) {
        int questionIndex = url.indexOf('?');
        if (questionIndex < 0 || questionIndex >= url.length() - 1) {
            return 0;
        }

        int count = 1;
        for (char ch : url.substring(questionIndex + 1).toCharArray()) {
            if (ch == '&') {
                count++;
            }
        }
        return count;
    }

    private String extractDomain(String url) {
        try {
            URL parsed = new URL(url);
            return parsed.getHost() == null ? "" : parsed.getHost().toLowerCase();
        } catch (Exception ex) {
            return "";
        }
    }

    private String getPrimaryDomain(String domain) {
        if (domain == null || domain.isBlank()) {
            return "";
        }
        String[] parts = domain.split("\\.");
        return parts.length >= 2 ? parts[parts.length - 2] : domain;
    }

    private String getTld(String domain) {
        if (domain == null || domain.isBlank() || !domain.contains(".")) {
            return "";
        }
        String[] parts = domain.split("\\.");
        return parts[parts.length - 1].toLowerCase();
    }

    private boolean isSuspiciousTld(String tld) {
        if (tld == null || tld.isBlank()) {
            return false;
        }

        for (String raw : suspiciousTldsCsv.split(",")) {
            if (tld.equals(raw.trim().toLowerCase())) {
                return true;
            }
        }
        return false;
    }

    private boolean hasSuspiciousDigitSubstitution(String primaryDomain) {
        if (primaryDomain == null || primaryDomain.isBlank()) {
            return false;
        }

        boolean hasLetter = false;
        boolean hasDigit = false;
        for (char ch : primaryDomain.toCharArray()) {
            if (Character.isLetter(ch)) {
                hasLetter = true;
            }
            if (Character.isDigit(ch)) {
                hasDigit = true;
            }
        }
        return hasLetter && hasDigit;
    }

    private int calculateFinalScore(int malware, int phishing, int piracy, int spam, int redirectRisk, int domainRisk) {
        double weighted = malware
                + phishing
                + (piracy * 0.6)
                + (spam * 0.4)
                + redirectRisk
                + domainRisk;

        return Math.max(0, Math.min(100, (int) Math.round(weighted)));
    }

    private String determineStatus(int malware, int phishing, int piracy, int spam, boolean trustedDomain, GoogleSafeBrowsingResult gsb) {
        if (malware >= 70) {
            return "DANGEROUS";
        }
        if (piracy >= 60) {
            return "SUSPICIOUS";
        }
        if (phishing >= 70 || spam >= 60) {
            return "SUSPICIOUS";
        }

        if (trustedDomain && !gsb.hasAnyThreat()) {
            return "SAFE";
        }

        return "SAFE";
    }

    private String determineMessage(String status, int malware, int phishing, int piracy, int spam) {
        if ("DANGEROUS".equals(status) && malware >= 70) {
            return "Malware risk confirmed by high-confidence signals";
        }
        if ("SUSPICIOUS".equals(status) && piracy >= 60) {
            return "Piracy-related behavior identified";
        }
        if ("SUSPICIOUS".equals(status) && spam >= 60) {
            return "Spam/ad-heavy behavior identified";
        }
        if (phishing >= 70) {
            return "Phishing-like patterns detected";
        }
        return "No malware detected";
    }

    private String toCategoryLabel(int score) {
        if (score >= 70) {
            return "HIGH";
        }
        if (score >= 30) {
            return "MEDIUM";
        }
        return "SAFE";
    }

    private String encodeUrlForVirusTotal(String url) {
        return Base64.getUrlEncoder().withoutPadding().encodeToString(url.getBytes(StandardCharsets.UTF_8));
    }

    private List<String> dedupeReasons(List<String> reasons) {
        return new ArrayList<>(new LinkedHashSet<>(reasons));
    }

    public String submitAsyncScan(String url) {
        cleanupExpiredAsyncJobs();
        long pendingJobs = asyncJobs.values().stream().filter(AsyncScanJob::isPending).count();
        if (pendingJobs >= maxAsyncJobs) {
            throw new ResponseStatusException(HttpStatus.TOO_MANY_REQUESTS, "Too many async scan jobs");
        }

        String normalized = normalizeUrl(url);
        String jobId = UUID.randomUUID().toString();
        AsyncScanJob job = new AsyncScanJob(jobId);
        asyncJobs.put(jobId, job);

        CompletableFuture
                .supplyAsync(() -> scanUrlInternal(normalized, true), asyncExecutor)
                .whenComplete((response, throwable) -> {
                    if (throwable != null) {
                        completeWithFallback(jobId, normalized);
                    } else {
                        completeJob(jobId, response);
                    }
                });

        asyncScheduler.schedule(() -> completeWithFallback(jobId, normalized), asyncTimeoutMs, TimeUnit.MILLISECONDS);
        return jobId;
    }

    public UrlScanAsyncStatusResponse getAsyncScanStatus(String jobId) {
        cleanupExpiredAsyncJobs();
        AsyncScanJob job = asyncJobs.get(jobId);
        if (job == null) {
            throw new ResponseStatusException(HttpStatus.NOT_FOUND, "Async scan job not found");
        }
        return new UrlScanAsyncStatusResponse(job.jobId, job.status, job.result, job.errorMessage);
    }

    private void completeWithFallback(String jobId, String url) {
        AsyncScanJob job = asyncJobs.get(jobId);
        if (job == null || !job.isPending()) {
            return;
        }

        UrlScanResponse fallback = scanUrlInternal(url, false);
        List<String> reasons = fallback.getReasons() == null ? new ArrayList<>() : new ArrayList<>(fallback.getReasons());
        reasons.add("Fallback mode activated due to async failure");
        fallback.setReasons(dedupeReasons(reasons));
        completeJob(jobId, fallback);
    }

    private void completeJob(String jobId, UrlScanResponse response) {
        AsyncScanJob job = asyncJobs.get(jobId);
        if (job == null) {
            return;
        }

        synchronized (job) {
            if (!job.isPending()) {
                return;
            }
            job.status = "COMPLETED";
            job.result = response;
            job.errorMessage = null;
            job.completedAtMs = System.currentTimeMillis();
        }
    }

    public void runScheduledAsyncCleanup() {
        cleanupExpiredAsyncJobs();
    }

    private void cleanupExpiredAsyncJobs() {
        long retentionMs = Math.max(0, asyncJobRetentionSeconds) * 1000;
        long now = System.currentTimeMillis();

        asyncJobs.entrySet().removeIf(entry -> {
            AsyncScanJob job = entry.getValue();
            if (job.isPending()) {
                return false;
            }
            if (retentionMs == 0) {
                return true;
            }
            return job.completedAtMs > 0 && (now - job.completedAtMs) >= retentionMs;
        });
    }

